#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MEMORY_SIZE 1000
#define MAX_PROCESSES 10

// Memory block structure
typedef struct {
 int process_id; // -1 if free
 int size;
 int start_address;
 int allocated; // 1 if allocated, 0 if free
} MemoryBlock;

// Process structure
typedef struct {
 int pid;
 int size;
 int address; // -1 if not allocated
} Process;

// Memory manager
typedef struct {
 MemoryBlock blocks[20];
 int block_count;
} MemoryManager;

// Initialize memory with one large free block
void init_memory(MemoryManager *mm) {
 mm->blocks[0].process_id = -1; // Free block
 mm->blocks[0].size = MEMORY_SIZE;
 mm->blocks[0].start_address = 0;
 mm->blocks[0].allocated = 0;
 mm->block_count = 1;
}

// First-Fit allocation algorithm
int allocate_first_fit(MemoryManager *mm, int pid, int size) {
 // Search for first free block large enough
 for (int i = 0; i < mm->block_count; i++) {
 if (mm->blocks[i].allocated == 0 && mm->blocks[i].size >= size) {
 // Found suitable block
 int old_size = mm->blocks[i].size;
 int old_address = mm->blocks[i].start_address;

 // Allocate the block
 mm->blocks[i].process_id = pid;
 mm->blocks[i].size = size;
 mm->blocks[i].allocated = 1;

 // If there's remaining space, create new free block
 if (old_size > size) {
 // Shift blocks to make room
 for (int j = mm->block_count; j > i + 1; j--) {
 mm->blocks[j] = mm->blocks[j-1];
 }

 // Create remaining free block
 mm->blocks[i+1].process_id = -1;
 mm->blocks[i+1].size = old_size - size;
 mm->blocks[i+1].start_address = old_address + size;
 mm->blocks[i+1].allocated = 0;

 mm->block_count++;
 }

 return old_address; // Return allocated address
 }
 }
 return -1; // No suitable block found
}

// Deallocate memory (coalesce adjacent free blocks)
void deallocate(MemoryManager *mm, int pid) {
 for (int i = 0; i < mm->block_count; i++) {
 if (mm->blocks[i].process_id == pid) {
 mm->blocks[i].process_id = -1;
 mm->blocks[i].allocated = 0;

 // Coalesce with adjacent free blocks
 coalesce_free_blocks(mm);
 return;
 }
 }
}

// Merge adjacent free blocks
void coalesce_free_blocks(MemoryManager *mm) {
 for (int i = 0; i < mm->block_count - 1; i++) {
 if (mm->blocks[i].allocated == 0 && mm->blocks[i+1].allocated == 0) {
 // Merge blocks
 mm->blocks[i].size += mm->blocks[i+1].size;

 // Shift remaining blocks
 for (int j = i + 1; j < mm->block_count - 1; j++) {
 mm->blocks[j] = mm->blocks[j+1];
 }
 mm->block_count--;
 }
 }
}

// Display memory state
void display_memory(MemoryManager *mm) {
 printf("\n=== Memory State ===\n");
 printf("Block# | PID | Address | Size | Status\n");
 printf("-------|------|----------|-------|--------\n");

 for (int i = 0; i < mm->block_count; i++) {
 printf("%6d | %4d | %8d | %5d | %s\n",
 i,
 mm->blocks[i].process_id,
 mm->blocks[i].start_address,
 mm->blocks[i].size,
 mm->blocks[i].allocated ? "ALLOC" : "FREE");
 }

 // Calculate statistics
 int free_mem = 0, used_mem = 0;
 for (int i = 0; i < mm->block_count; i++) {
 if (mm->blocks[i].allocated == 0)
 free_mem += mm->blocks[i].size;
 else
 used_mem += mm->blocks[i].size;
 }
 printf("\nTotal: %d, Used: %d, Free: %d\n", 
 MEMORY_SIZE, used_mem, free_mem);
}

int main() {
 MemoryManager memory;
 init_memory(&memory);

 printf("=== First-Fit Memory Allocation Demo ===\n");
 printf("Total Memory Size: %d\n", MEMORY_SIZE);

 // Allocate processes
 int processes[][2] = {{1, 200}, {2, 300}, {3, 150}, {4, 100}};
 int num_procs = 4;

 printf("\n--- Allocating Processes ---\n");
 for (int i = 0; i < num_procs; i++) {
 int addr = allocate_first_fit(&memory, processes[i][0], processes[i][1]);
 if (addr >= 0) {
 printf("Process %d: Allocated at address %d, size %d\n",
 processes[i][0], addr, processes[i][1]);
 } else {
 printf("Process %d: Allocation FAILED (not enough memory)\n",
 processes[i][0]);
 }
 }

 display_memory(&memory);

 // Deallocate process 2
 printf("\n--- Deallocating Process 2 ---\n");
 deallocate(&memory, 2);
 display_memory(&memory);

 // Try to allocate larger process (demonstrates fragmentation)
 printf("\n--- Trying to allocate Process 5 (size 400) ---\n");
 int addr = allocate_first_fit(&memory, 5, 400);
 if (addr >= 0) {
 printf("Process 5: Allocated at address %d\n", addr);
 } else {
 printf("Process 5: Allocation FAILED\n");
 printf("Note: Total free = 500, but largest block is smaller!\n");
 }

 display_memory(&memory);

 return 0;
}
